fn to_base36(num: u64) -> String {
    if num == 0 {
        return "0".to_string();
    }
    let mut digits = Vec::new();
    let mut n = num;
    while n > 0 {
        let remainder = n % 36;
        let c = if remainder < 10 {
            (b'0' + remainder as u8) as char
        } else {
            (b'A' + (remainder - 10) as u8) as char
        };
        digits.push(c);
        n = n / 36;
    }
    digits.into_iter().rev().collect()
}

